const COMPARE_COL = 'unit_cost_1';
const ID_COLS = ['product_id_1', 'product_name_1', 'mailing_method_name', 'day', 'min_quantity'];

function parseCSV(content) {
  const clean = content.replace(/^\uFEFF/, '').replace(/\r\n/g, '\n').replace(/\r/g, '\n').trim();
  const match = clean.match(/(product_id_1,[\s\S]*)/);
  if (!match) return {};
  const csvPart = match[1].trim();
  const lines = csvPart.split('\n').filter(l => l.trim());
  const headers = lines[0].split(',').map(h => h.trim());
  return lines.slice(1).map(line => {
    const vals = line.split(',');
    return Object.fromEntries(headers.map((h, i) => [h, (vals[i] || '').trim()]));
  });
}

function rowKey(row) {
  return ID_COLS.map(c => row[c] || '').join('|');
}

const csv1 = $('qa2').item.json.stdout;
const csv2 = $('qa5').item.json.stdout;
const productId = $('Loop Over Items').item.json.product_ids;
const categoryId = $('Master Data Form').item.json.category_id;

const rows1 = parseCSV(csv1);
const rows2 = parseCSV(csv2);

const map1 = Object.fromEntries(rows1.map(r => [rowKey(r), r]));
const map2 = Object.fromEntries(rows2.map(r => [rowKey(r), r]));
const allKeys = [...new Set([...Object.keys(map1), ...Object.keys(map2)])];

const diffs = [];
const only1 = [];
const only2 = [];

for (const key of allKeys) {
  const r1 = map1[key];
  const r2 = map2[key];
  if (r1 && !r2) { only1.push(r1); continue; }
  if (r2 && !r1) { only2.push(r2); continue; }
  const v1 = r1[COMPARE_COL] || '';
  const v2 = r2[COMPARE_COL] || '';
  if (v1 !== v2) {
    const n1 = parseFloat(v1), n2 = parseFloat(v2);
    const delta = (!isNaN(n1) && !isNaN(n2))
      ? (() => { const d = Math.round((n2 - n1) * 10000) / 10000; return d > 0 ? `+${d}` : `${d}`; })()
      : 'N/A';
    diffs.push({
      product_id: r1.product_id_1 || '',
      day: r1.day || '',
      min_qty: r1.min_quantity || '',
      val1: v1, val2: v2, delta
    });
  }
}

return {
  json: {
    product_id: productId,
    category_id: categoryId,
    env1: $input.item.json.original_env,
    env2: $input.item.json.env,
    diffs,
    only1_count: only1.length,
    only2_count: only2.length,
    total_rows: allKeys.length
  }
};

const item = $input.first().json;
const raw = item.product_ids;

// clean up the string "[\"6\",\"7\"]" → ["6","7"]
const ids = raw.replace(/[\[\]\s"]/g, '').split(',').filter(s => s !== '');

return ids.map(id => ({
  json: { ...item, product_ids: id }
}));

// ── Report Code node ───────────────────────────────────────────────────────
// Mode: Run Once for All Items
// Paste this into the Report Code node in n8n

const items = $input.all();
const allProducts = items[0].json.data && Array.isArray(items[0].json.data)
  ? items[0].json.data
  : items.map(i => i.json);

const ENV1 = (allProducts[0]?.env1 || 'ENV1').toUpperCase();
const ENV2 = (allProducts[0]?.env2 || 'ENV2').toUpperCase();
const CATEGORY_ID = allProducts[0]?.category_id || '?';
const productList = allProducts.map(p => p.product_id).filter(Boolean).join(', ');

let totalDiffs = 0;
let totalRows = 0;
let only1Total = 0;
let only2Total = 0;
let rowsHtml = '';

for (const product of allProducts) {
  totalRows += product.total_rows || 0;
  only1Total += product.only1_count || 0;
  only2Total += product.only2_count || 0;
  const diffs = product.diffs || [];
  totalDiffs += diffs.length;

  if (diffs.length > 0) {
    rowsHtml += diffs.map(d => {
      const dc = d.delta.startsWith('+') ? 'up' : 'down';
      return `<tr>
        <td>${d.product_id}</td>
        <td class="jp">${d.product_name}</td>
        <td class="jp">${d.mailing_method}</td>
        <td>${d.day}</td>
        <td>${d.min_qty}</td>
        <td class="mono e1">${d.val1}</td>
        <td class="mono e2">${d.val2}</td>
        <td class="mono ${dc}">${d.delta}</td>
      </tr>`;
    }).join('');
  }
}

if (!rowsHtml) {
  rowsHtml = '<tr><td colspan="8" class="nodiff">No differences in unit_cost_1 — all products identical</td></tr>';
}

const now = new Date().toLocaleString('ja-JP');
const statClass = totalDiffs > 0 ? 'red' : 'green';
const missingHtml = [
  only1Total ? `<p class="warn">⚠ ${only1Total} rows only in ${ENV1}</p>` : '',
  only2Total ? `<p class="warn">⚠ ${only2Total} rows only in ${ENV2}</p>` : ''
].join('');

const productSummaryRows = allProducts.map(p => `
  <tr>
    <td>${p.product_id || '-'}</td>
    <td class="jp">${(p.diffs && p.diffs[0]) ? p.diffs[0].product_name : '-'}</td>
    <td>${p.total_rows || 0}</td>
    <td class="${(p.diffs?.length || 0) > 0 ? 'red-text' : 'green-text'}">${p.diffs?.length || 0}</td>
  </tr>`).join('');

const html = `<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8">
<title>unit_cost_1 diff · ${ENV1} vs ${ENV2}</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#f5f5f5;color:#1a1a1a;font-size:14px}
.hdr{background:#1a1a1a;color:#fff;padding:1.5rem 2rem}
.hdr h1{font-size:1.15rem;font-weight:600;margin-bottom:.4rem}
.meta{display:flex;gap:1.5rem;flex-wrap:wrap;margin-top:.5rem}
.meta-item{font-size:.8rem;color:#aaa}
.meta-item span{color:#fff;font-weight:500}
.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:1rem;padding:1.25rem 2rem}
.stat{background:#fff;border-radius:8px;padding:1rem 1.25rem;border:1px solid #e5e5e5}
.stat .num{font-size:1.75rem;font-weight:700}
.stat .lbl{font-size:.72rem;color:#888;margin-top:.2rem}
.red .num{color:#dc2626}.green .num{color:#16a34a}
.red-text{color:#dc2626;font-weight:600}
.green-text{color:#16a34a}
.section{padding:0 2rem 1.5rem}
.section-title{font-size:.7rem;font-weight:600;color:#888;text-transform:uppercase;letter-spacing:.06em;margin-bottom:.75rem}
.summary-table{width:100%;border-collapse:collapse;background:#fff;border-radius:8px;overflow:hidden;border:1px solid #e5e5e5;margin-bottom:1.5rem}
.summary-table th{padding:.6rem 1rem;text-align:left;font-weight:600;font-size:.72rem;color:#555;border-bottom:1px solid #e5e5e5;background:#f9f9f9}
.summary-table td{padding:.55rem 1rem;border-bottom:1px solid #f0f0f0;font-size:.85rem}
.summary-table tr:last-child td{border-bottom:none}
.summary-table tr:hover td{background:#fafafa}
.wrap{padding:0 2rem 2rem}
.warn{color:#b45309;background:#fef3c7;padding:.5rem 1rem;border-radius:6px;margin-bottom:.75rem;font-size:.8rem}
.search{margin-bottom:.875rem}
.search input{width:100%;padding:.5rem .875rem;border:1px solid #ddd;border-radius:6px;font-size:.875rem;outline:none}
.search input:focus{border-color:#666}
table{width:100%;border-collapse:collapse;background:#fff;border-radius:8px;overflow:hidden;border:1px solid #e5e5e5}
thead{background:#f9f9f9}
th{padding:.6rem .875rem;text-align:left;font-weight:600;font-size:.72rem;color:#555;border-bottom:1px solid #e5e5e5;white-space:nowrap}
td{padding:.5rem .875rem;border-bottom:1px solid #f0f0f0;vertical-align:middle}
tr:last-child td{border-bottom:none}
tr:hover td{background:#fafafa}
.mono{font-family:monospace;font-size:.8rem}
.up{color:#dc2626;font-weight:600}.down{color:#16a34a;font-weight:600}
.jp{font-size:.78rem}
.nodiff{text-align:center;padding:2rem;color:#16a34a;font-weight:500}
.hidden{display:none}
.e1{color:#1d4ed8}.e2{color:#166534}
