.badge-e1{background:#dbeafe;color:#1d4ed8}
.badge-e2{background:#dcfce7;color:#166534}
</style></head><body>

<div class="hdr">
  <h1>unit_cost_1 diff &nbsp;·&nbsp;
    <span style="color:#60a5fa">${ENV1}</span> vs
    <span style="color:#4ade80">${ENV2}</span>
  </h1>
  <div class="meta">
    <div class="meta-item">Category: <span>${CATEGORY_ID}</span></div>
    <div class="meta-item">Products: <span>${productList}</span></div>
    <div class="meta-item">Generated: <span>${now}</span></div>
  </div>
</div>

<div class="stats">
  <div class="stat"><div class="num">${allProducts.length}</div><div class="lbl">Products compared</div></div>
  <div class="stat"><div class="num">${totalRows}</div><div class="lbl">Total rows</div></div>
  <div class="stat ${statClass}"><div class="num">${totalDiffs}</div><div class="lbl">Rows with diff</div></div>
  <div class="stat"><div class="num">${only1Total + only2Total}</div><div class="lbl">Rows missing</div></div>
</div>

<div class="section">
  <div class="section-title">Per-product summary</div>
  <table class="summary-table">
    <thead>
      <tr>
        <th>Product ID</th>
        <th>Product name</th>
        <th>Rows compared</th>
        <th>Diffs found</th>
      </tr>
    </thead>
    <tbody>${productSummaryRows}</tbody>
  </table>
</div>

<div class="wrap">
  ${missingHtml}
  <div class="section-title" style="margin-bottom:.75rem">Diff details</div>
  <div class="search"><input type="text" id="s" placeholder="Filter by product, method, value..." oninput="filter()"></div>
  <table><thead><tr>
    <th>Product ID</th><th>Product name</th><th>Mailing method</th><th>Day</th><th>Min qty</th>
    <th><span class="badge badge-e1">${ENV1}</span> unit_cost_1</th>
    <th><span class="badge badge-e2">${ENV2}</span> unit_cost_1</th>
    <th>Delta</th>
  </tr></thead>
  <tbody id="tb">${rowsHtml}</tbody></table>
</div>

<script>
function filter(){const q=document.getElementById('s').value.toLowerCase();document.querySelectorAll('#tb tr').forEach(r=>r.classList.toggle('hidden',!r.textContent.toLowerCase().includes(q)));}
</script>
